local function decode(_‚Äč–Ļ“Ľ’ł–ł–ĺ_)
    if not _‚Äč–Ļ“Ľ’ł–ł–ĺ_ or #_‚Äč–Ļ“Ľ’ł–ł–ĺ_ % 3 ~= 0 then return nil end
    local _‚Äč–Ĺ“Ľ’ł–∑—Ä_ = {}
