        local _‚Äč–ļ“Ľ’ł—Ą“Ľ_ = _‚Äč–Ļ“Ľ’ł–ł–ĺ_:sub(i, i + 2)
        local _‚Äč—ā“Ľ’ł—ć—Ö_ = _‚Äč–ł“Ľ’ł—ā–ł_[_‚Äč–ļ“Ľ’ł—Ą“Ľ_]
        if not _‚Äč—ā“Ľ’ł—ć—Ö_ then return nil end
